+/** A condition accepted by the conditional option helpers. */
+export type OptionCondition =
+  | string
+  | OptionDependencyCondition
+  | OptionDependency;
+
+function normalizeOptionDependency(condition: OptionCondition): OptionDependency {
+  return typeof condition === "string" ? { option: condition } : condition;
+}
+
+function createConditionalOption<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser: ValueParser<M, T> | undefined,
+  required: boolean | undefined,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  const names = (typeof flagSpec === "string" ? [flagSpec] : flagSpec) as readonly OptionName[];
+  const dependsOn = {
+    ...normalizeOptionDependency(condition),
+    ...(required === undefined ? {} : { required }),
+  };
+  if (valueParser) {
+    return option(
+      ...(names as readonly [...OptionName[], ValueParser<M, T>, OptionOptions]),
+      valueParser,
+      { dependsOn },
+    ) as Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined>;
+  }
+  return option(
+    ...(names as readonly [...OptionName[], OptionOptions]),
+    { dependsOn },
+  ) as Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined>;
+}
+
+/**
+ * Creates an option whose condition must be satisfied when it is supplied.
+ * @since 0.10.0
+ */
+export function requiredWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  return createConditionalOption(condition, flagSpec, valueParser, true);
+}
+
+/**
+ * Creates an option that is hidden while its condition is unsatisfied.
+ * @since 0.10.0
+ */
+export function optionalWhen<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  return createConditionalOption(condition, flagSpec, valueParser, false);
+}
+
+/**
+ * Creates an option with conditional visibility and optional strict validation.
+ * @since 0.10.0
+ */
+export function conditionalOption<M extends Mode, T>(
+  condition: OptionCondition,
+  flagSpec: OptionName | readonly OptionName[],
+  valueParser?: ValueParser<M, T>,
+): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
+  return createConditionalOption(condition, flagSpec, valueParser, undefined);
+}

