+function findOptionNames(usage: Usage): readonly string[] | undefined {
+  for (const term of usage) {
+    if (term.type === "option") return term.names;
+    if (term.type === "optional" || term.type === "multiple") {
+      const names = findOptionNames(term.terms);
+      if (names) return names;
+    } else if (term.type === "exclusive") {
+      for (const terms of term.terms) {
+        const names = findOptionNames(terms);
+        if (names) return names;
+      }
+    }
+  }
+  return undefined;
+}
+
+function getConditionalStateValue(state: unknown): ConditionalStateValue {
+  if (isDependencySourceState(state)) return getConditionalStateValue(state.result);
+  if (Array.isArray(state)) {
+    return state.length === 1
+      ? getConditionalStateValue(state[0])
+      : { available: false, value: undefined };
+  }
+  if (state !== null && typeof state === "object") {
+    if ("success" in state && "value" in state) {
+      const result = state as { readonly success: boolean; readonly value: unknown };
+      return result.success
+        ? { available: true, value: result.value }
+        : { available: false, value: undefined };
+    }
+    if ("value" in state) {
+      return { available: true, value: (state as { readonly value: unknown }).value };
+    }
+  }
+  return { available: false, value: undefined };
+}
+
+function evaluateCondition(
+  condition: OptionDependencyCondition,
+  states: Record<string | symbol, unknown>,
+  optionFields: ReadonlyMap<string, string | symbol>,
+): boolean {
+  const field = Object.prototype.hasOwnProperty.call(states, condition.option)
+    ? condition.option
+    : optionFields.get(condition.option);
+  if (field === undefined) return false;
+  const state = getConditionalStateValue(states[field]);
+  if (!state.available) return false;
+  return Object.prototype.hasOwnProperty.call(condition, "value")
+    ? state.value === condition.value
+    : Boolean(state.value);
+}
+
+function isDependencySatisfied(
+  dependency: OptionDependency,
+  states: Record<string | symbol, unknown>,
+  optionFields: ReadonlyMap<string, string | symbol>,
+): boolean {
+  const single = dependency.option === undefined ? undefined : {
+    option: dependency.option,
+    ...(Object.prototype.hasOwnProperty.call(dependency, "value")
+      ? { value: dependency.value }
+      : {}),
+  };
+  if (single) return evaluateCondition(single, states, optionFields);
+  if (dependency.allOf) {
+    return dependency.allOf.every((condition) =>
+      evaluateCondition(condition, states, optionFields)
+    );
+  }
+  if (dependency.anyOf) {
+    return dependency.anyOf.some((condition) =>
+      evaluateCondition(condition, states, optionFields)
+    );
+  }
+  return false;
+}
