+import { object } from "./constructs.ts";
+import { formatMessage } from "./message.ts";
+import { withDefault } from "./modifiers.ts";
+import {
+  conditionalOption,
+  option,
+  optionalWhen,
+  requiredWhen,
+} from "./primitives.ts";
+import { getDocPageSync, parseSync, suggestSync } from "./parser.ts";
+import { integer, string } from "./valueparser.ts";
+import assert from "node:assert/strict";
+import { describe, it } from "node:test";
+
+describe("conditional options", () => {
+  it("maps a CLI flag dependency to its object key", () => {
+    const parser = object({
+      mode: option("--mode", string()),
+      config: requiredWhen({ option: "--mode", value: "prod" }, "--config", string()),
+    });
+
+    const valid = parseSync(parser, ["--mode", "prod", "--config", "app.toml"]);
+    assert.ok(valid.success);
+
+    const invalid = parseSync(parser, ["--config", "app.toml"]);
+    assert.ok(!invalid.success);
+    assert.match(formatMessage(invalid.error), /requires option/);
+    assert.match(formatMessage(invalid.error), /--mode/);
+    assert.match(formatMessage(invalid.error), /prod/);
+  });
+
+  it("supports object keys, compound conditions, and empty groups", () => {
+    const parser = object({
+      alpha: option("--alpha"),
+      beta: option("--beta"),
+      all: conditionalOption({ allOf: [] }, "--all"),
+      any: conditionalOption({ anyOf: [] }, "--any"),
+      target: requiredWhen({ anyOf: [{ option: "alpha" }, { option: "beta" }] }, "--target"),
+    });
+
+    assert.ok(parseSync(parser, ["--all"]).success);
+    assert.ok(parseSync(parser, ["--alpha", "--target"]).success);
+    assert.ok(!parseSync(parser, ["--target"]).success);
+  });
+
+  it("retains dependency metadata through withDefault for help and completion", () => {
+    const parser = object({
+      enabled: option("--enabled"),
+      output: withDefault(optionalWhen("enabled", "--output", string()), "out"),
+    });
+
+    const doc = getDocPageSync(parser);
+    assert.ok(doc);
+    const entries = doc.sections.flatMap((section) => section.entries);
+    assert.ok(!entries.some((entry) => entry.term.type === "option" && entry.term.names.includes("--output")));
+    assert.ok(!suggestSync(parser, [""]).some((suggestion) => suggestion.text === "--output"));
+
+    const enabledDoc = getDocPageSync(parser, ["--enabled"]);
+    assert.ok(enabledDoc?.sections.flatMap((section) => section.entries).some((entry) =>
+      entry.term.type === "option" && entry.term.names.includes("--output")
+    ));
+  });
+
+  it("allows hidden optional options but rejects an explicit falsy dependee", () => {
+    const parser = object({
+      enabled: option("--enabled", integer()),
+      output: optionalWhen("enabled", "--output", string()),
+    });
+
+    assert.ok(parseSync(parser, ["--output", "out"]).success);
+    const result = parseSync(parser, ["--enabled", "0", "--output", "out"]);
+    assert.ok(!result.success);
+    assert.match(formatMessage(result.error), /requires option --enabled/);
+  });
+});
